package com.example.princesa_disney.entityimport androidx.room.ColumnInfoimport androidx.room.Entityimport androidx.room.PrimaryKey@Entity(tableName = "User")data class User(    @PrimaryKey(autoGenerate = true) @ColumnInfo(name = "id") val id: Int = 0,    @ColumnInfo(name = "email") val email: String,    @ColumnInfo(name = "senha") val senha: String)